  UPDATE pages_fts
  SET tags_text = (
    SELECT COALESCE(GROUP_CONCAT(t.label_ja || ' ' || t.label_en, ' '), '')
    FROM page_tags pt
    JOIN tags t ON t.slug = pt.tag_slug
    WHERE pt.page_id = new.page_id
  )
  WHERE page_id = new.page_id;
END;
