CREATE TABLE page_embedding_status (
  page_id TEXT PRIMARY KEY REFERENCES pages(id) ON DELETE CASCADE,
  status TEXT NOT NULL DEFAULT 'pending',
  -- 'pending' | 'indexed' | 'error'
